def solve(frames: List[str]) -> Dict[str, float]:
    """
    Decode base64 frames, each containing a JSON object with channels mapping to token lists.
    For each channel, compute the normalized sum (sum / length) per frame, then average across frames.
    """
    if not frames:
        return {}

    channel_sums: Dict[str, float] = {}
    num_frames = len(frames)

    for frame in frames:
        try:
            decoded_bytes = base64.b64decode(frame)
            decoded_str = decoded_bytes.decode('utf-8')
            data = json.loads(decoded_str)
        except (ValueError, json.JSONDecodeError, UnicodeDecodeError):
            # If decoding fails, skip this frame
            continue

        if not isinstance(data, dict):
            continue

        for channel, tokens in data.items():
            if not isinstance(tokens, list):
                continue
            # Compute normalized sum for this channel in this frame
            if len(tokens) > 0:
                norm_sum = sum(tokens) / len(tokens)
            else:
                norm_sum = 0.0

            channel_sums[channel] = channel_sums.get(channel, 0.0) + norm_sum

    # Average across frames
    return {ch: total / num_frames for ch, total in channel_sums.items()}
