from collections import defaultdict

def solve(frames: list[str]) -> dict[str, float]:
    # Helper to convert a hex string (with optional 0x prefixes and spaces) to bytes.
    def to_bytes(s: str) -> bytes | None:
        s = s.strip()
        # Remove any non-hex characters.
        s = re.sub(r'[^0-9a-fA-F]', '', s)
        if len(s) % 2 != 0:
            return None
        try:
            return bytes.fromhex(s)
        except ValueError:
            return None

    # Validate the frame: first byte 0x55, last byte is XOR checksum of the rest.
    def is_valid(data: bytes) -> bool:
        if len(data) < 3:
            return False
        if data[0] != 0x55:
            return False
        chk = 0
        for b in data[:-1]:
            chk ^= b
        return chk == data[-1]

    channel_data = defaultdict(list)

    for frame_str in frames:
        data = to_bytes(frame_str)
        if data is None:
            continue
        if not is_valid(data):
            continue

        channel = data[1]          # second byte is channel
        tokens = data[2:-1]        # everything between channel and checksum
        if not tokens:
            continue

        token_sum = sum(tokens)
        # Normalize by dividing by the maximum possible token value (255).
        normalized = token_sum / 255.0
        channel_data[channel].append(normalized)

    # Compute average per channel.
    result = {}
    for ch, vals in channel_data.items():
        avg = sum(vals) / len(vals)
        result[str(ch)] = avg

    return result
