from collections import Counter, defaultdict

def solve(histories: list[list[dict]]) -> str:
    if not histories:
        return 'intern'

    suggestions = []
    for history in histories:
        if not history:
            # empty history: default suggestion
            suggestions.append('intern')
            continue

        # count roles in this history, preserving order of first occurrence
        role_counter = Counter()
        first_seen = {}
        for entry in history:
            role = entry.get('role', None)
            if role is None:
                role = 'intern'  # fallback
            role_counter[role] += 1
            if role not in first_seen:
                first_seen[role] = len(first_seen)

        # find most common role; if tie, earliest first occurrence
        max_count = 0
        best_role = None
        # iterate in order of first appearance
        for role in sorted(first_seen.keys(), key=lambda r: first_seen[r]):
            cnt = role_counter[role]
            if cnt > max_count:
                max_count = cnt
                best_role = role
        suggestions.append(best_role)

    # now find most common suggestion overall; tie-break by first appearance in suggestions
    suggestion_counter = Counter()
    suggestion_order = {}
    for idx, sug in enumerate(suggestions):
        suggestion_counter[sug] += 1
        if sug not in suggestion_order:
            suggestion_order[sug] = idx

    max_count = 0
    best_suggestion = None
    # iterate in order of first appearance in suggestions (i.e., by order of histories)
    for sug in sorted(suggestion_order.keys(), key=lambda s: suggestion_order[s]):
        cnt = suggestion_counter[sug]
        if cnt > max_count:
            max_count = cnt
            best_suggestion = sug
    return best_suggestion
