def solve(subject: str, resources: list[str], policies: list[str]) -> dict[str, list[str]]:
    allowed = {res: set() for res in resources}
    denied = {res: set() for res in resources}

    for policy in policies:
        # Normalize: lowercase effect and handle possible extra words "to" and "on"
        tokens = policy.split()
        if not tokens:
            continue
        # Remove common filler words if present
        filler = {"to", "on", "the", "and"}
        cleaned = [t for t in tokens if t.lower() not in filler]
        if len(cleaned) < 4:
            continue  # skip malformed policies
        effect = cleaned[0].lower()  # allow or deny
        policy_subj = cleaned[1]     # subject or wildcard '*'
        # actions can be comma-separated (e.g., "read,write")
        actions = [a.strip() for a in cleaned[2].split(',')]
        # resource pattern, possibly wildcard '*'
        policy_res = cleaned[3]

        if effect not in ('allow', 'deny'):
            continue

        for resource in resources:
            if not (policy_res == resource or policy_res == '*'):
                continue
            if not (policy_subj == subject or policy_subj == '*'):
                continue

            if effect == 'allow':
                allowed[resource].update(actions)
            else:  # deny
                denied[resource].update(actions)

    result = {}
    for res in resources:
        final_actions = sorted(allowed[res] - denied[res])
        result[res] = final_actions
    return result
