        if s[i] == '(':
            tokens.append(('LPAREN', '('))
            i += 1
        elif s[i] == ')':
            tokens.append(('RPAREN', ')'))
            i += 1
        elif s[i] == ',':
            tokens.append(('COMMA', ','))
            i += 1
        elif s[i] == '"':
            i += 1
            start = i
            while i < n and s[i] != '"':
                i += 1
            if i >= n:
                raise ValueError("Unclosed string")
            value = s[start:i]
            i += 1
            tokens.append(('STRING', value))
        elif s[i].isdigit() or (s[i] == '-' and i + 1 < n and s[i + 1].isdigit()):
            start = i
            if s[i] == '-':
                i += 1
            while i < n and s[i].isdigit():
                i += 1
            num_str = s[start:i]
            tokens.append(('NUMBER', int(num_str)))
        else:
            raise ValueError(f"Unexpected character: {s[i]}")
    return tokens

