def solve(series: str) -> float:
    """
    Parse the series string and return the mean from its statistical summary.
    Supports formats like:
      - Python dictionary string: "{'mean': 3.5, 'median': 2.0}"
      - Key-value pairs: "mean=3.5, median=2.0"
      - Colon separated: "mean: 3.5; median: 2.0"
      - Simple spaced: "mean 3.5"
    """
    series = series.strip()
    if not series:
        raise ValueError("Empty series string")

    # Try to parse as a Python dict literal
    if series.startswith('{'):
        try:
            data = ast.literal_eval(series)
            if isinstance(data, dict):
                return _extract_mean_from_dict(data)
        except (ValueError, SyntaxError):
            pass

    # Fall back to regex extraction: look for "mean" followed by optional separators and a number
    pattern = re.compile(
        r'[Mm]ean\s*[=:]\s*([+-]?\d+\.?\d*(?:[eE][+-]?\d+)?)'
    )
    match = pattern.search(series)
    if match:
        return float(match.group(1))

    # Try pattern without explicit separator (e.g., "mean 3.5")
    pattern2 = re.compile(
        r'[Mm]ean\s+([+-]?\d+\.?\d*(?:[eE][+-]?\d+)?)'
    )
    match2 = pattern2.search(series)
    if match2:
        return float(match2.group(1))

    # If all else fails, try to interpret the string as a list of numbers and compute mean
    # This handles a plain series like "1,2,3" or "1 2 3"
    try:
        numbers = [float(x) for x in re.split(r'[,\s]+', series) if x]
        if numbers:
            return sum(numbers) / len(numbers)
    except ValueError:
        pass

    raise ValueError("Could not parse mean from series string")

def _extract_mean_from_dict(data: Dict[str, Any]) -> float:
