def solve(series_list: list[str]) -> list[float]:
    # Parse all (timestamp, value) pairs from all series
    pairs = []
    for series in series_list:
        # Each series: "t1:v1,t2:v2,..."
        if not series:
            continue
        tokens = series.split(',')
        for token in tokens:
            if not token:
