    max_val = max(filtered_vals)

    # Min-max normalization
    if max_val == min_val:
        # All values same -> return zeros
        return [0.0] * len(filtered_vals)

    norm_vals = [(v - min_val) / (max_val - min_val) for v in filtered_vals]
    return norm_vals
