    forecasts = []
    for series in series_list:
        # Parse series string: "timestamp:value;timestamp:value;..."
        entries = series.split(';')
        pairs = []
        for entry in entries:
            entry = entry.strip()
            if not entry:
                continue
            t_str, v_str = entry.split(':')
            t = float(t_str.strip())
            v = float(v_str.strip())
            pairs.append((t, v))
        if not pairs:
            continue
        # Last observation
        last_t, last_v = pairs[-1]
        # Determine next timestamp
        if len(pairs) >= 2:
            step = pairs[-1][0] - pairs[-2][0]
        else:
            step = 1.0  # default step if only one point
        next_t = last_t + step
        # Format forecast entry
        # Use integer format if no fractional part
        def fmt_num(x):
            return str(int(x)) if x == int(x) else str(x)
        forecast_entry = f"{fmt_num(next_t)}:{fmt_num(last_v)}"
        forecasts.append(forecast_entry)
    return ';'.join(forecasts)
