def solve(series_list: list[str]) -> float:
    differences = []
    for series in series_list:
        if not series.strip():
            continue
        # Split by commas, then strip whitespace
        parts = series.split(',')
        numbers = []
        for p in parts:
            p = p.strip()
            if p:
                numbers.append(float(p))
        # Compute consecutive differences
        for i in range(1, len(numbers)):
            differences.append(numbers[i] - numbers[i-1])
    if not differences:
        return 0.0
    return sum(differences) / len(differences)
